output.sparql:
PREFIX pq: <http://www.wikidata.org/prop/qualifier/>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX p: <http://www.wikidata.org/prop/>
PREFIX ps: <http://www.wikidata.org/prop/statement/>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT DISTINCT ?monarch ?monarchLabel WHERE {
  ?monarch p:P39 ?statement .
  ?statement ps:P39 ?position .
  VALUES ?position {
    wd:Q9134365 wd:Q111722535
  }
  .
  ?statement pq:P580 ?start ; pq:P582 ?end .
  FILTER(xsd:dateTime(?start) <= "2000-12-31T23:59:59Z" ^^ xsd:dateTime && xsd:dateTime(?end) >= "1901-01-01T00:00:00Z" ^^ xsd:dateTime)
  OPTIONAL {
    ?monarch rdfs:label ?monarchLabel .
    FILTER(lang(?monarchLabel) = "en")
  }
}

